package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.finance.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;
@RestController @RequestMapping("/internal/supplier/v1/bms/events")public class BmsFinanceOpenApiController{private final BmsFinanceEventConsumerApplicationService service;public BmsFinanceOpenApiController(BmsFinanceEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Request b,HttpServletRequest r){if(!"BMS".equals(r.getHeader("X-Source-System")))throw new BusinessException(ErrorCode.FORBIDDEN,"来源系统必须为BMS");String code=r.getHeader("X-Event-Code");if(code==null||code.isBlank())throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少事件编码");service.consume(new BmsFinanceEvent(code,b.eventType(),b.statementNo(),b.supplierId(),b.currency(),b.amount(),b.sourceVersion(),b.invoiceId(),b.passed(),b.message()));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,String statementNo,long supplierId,String currency,BigDecimal amount,int sourceVersion,Long invoiceId,boolean passed,String message){} }
